122	        </View>
123	        <View className="form-row">
124	          <View className="form-group flex-1">
125	            <Text className="form-label">起床时间</Text>
126	            <Picker mode="time" value={profile.wakeTime} onChange={(e) => setProfile({ ...profile, wakeTime: e.detail.value })}>
127	              <View className="form-input" style={{ display: "flex", alignItems: "center" }}><Text>{profile.wakeTime}</Text></View>
128	            </Picker>
129	          </View>
130	          <View className="form-group flex-1">
131	            <Text className="form-label">睡觉时间</Text>
132	            <Picker mode="time" value={profile.sleepTime} onChange={(e) => setProfile({ ...profile, sleepTime: e.detail.value })}>
133	              <View className="form-input" style={{ display: "flex", alignItems: "center" }}><Text>{profile.sleepTime}</Text></View>
134	            </Picker>
135	          </View>
136	        </View>
137	      </View>
138	
139	      <View className="card">
140	        <Text className="card-title">你的目标</Text>
141	        <Textarea className="form-textarea" placeholder={"提升商业分析能力\n养成运动习惯\n扩大社交圈\n..."} value={profile.goals} onInput={(e) => setProfile({ ...profile, goals: e.detail.value })} />
142	      </View>
143	
144	      <View className="card">
145	        <Text className="card-title">AI 个性化提示词</Text>
146	        <Textarea className="form-textarea" placeholder={"用「陛下」称呼我\n关注商业和管理领域\n多推荐前沿科技内容"} value={profile.customPrompt} onInput={(e) => setProfile({ ...profile, customPrompt: e.detail.value })} />
147	      </View>
148	
149	      <View className="save-btn" onClick={saveProfile}>
150	        <Text>{saved ? "已保存 ✓" : "保存设置"}</Text>
151	      </View>
152	
153	      <ReminderCard
154	        enabled={reminderEnabled}
155	        time={reminderTime}
156	        days={reminderDays}
157	        onToggle={handleReminderToggle}
158	        onTimeChange={handleReminderTimeChange}
159	        onDayToggle={handleReminderDayToggle}
160	      />
161	
162	      <View className="card">
163	        <Text className="card-title">个性化需求</Text>
164	        <View style={{ marginBottom: "20rpx" }}>
165	          {inputs.map((pi, i) => (
166	            <Text key={i} className="input-tag">{pi.category}: {pi.content}</Text>
167	          ))}
168	        </View>
169	        <View className="input-row">
170	          <Picker mode="selector" range={PRESET_DOMAINS.map(d => d.name)} value={PRESET_DOMAINS.findIndex(d => d.name === newInput.category)} onChange={(e) => setNewInput({ ...newInput, category: PRESET_DOMAINS[+e.detail.value].name })}>
171	            <View className="form-input" style={{ width: "160rpx", display: "flex", alignItems: "center" }}><Text>{newInput.category}</Text></View>
172	          </Picker>
173	          <Input className="form-input" style={{ flex: 1 }} placeholder="描述你的个性化需求..." value={newInput.content} onInput={(e) => setNewInput({ ...newInput, content: e.detail.value })} onConfirm={addInput} />
174	          <Text className="add-btn" onClick={addInput}>添加</Text>
175	        </View>
176	      </View>
177	    </View>
178	  );
179	}
